select * from problem_feedback

    deleted = 0

        and user_type = #{userType}


        and status = #{status}


        and priority = #{priority}


        and feedback_type = #{feedbackType}


        and user_name like concat('%',#{userName},'%')


        and title like concat('%',#{title},'%')


order by status = 'processing' DESC, FIELD(priority, 'high', 'normal', 'low'), create_time desc

SELECT * FROM problem_feedback WHERE deleted = 0 
ORDER BY status = 'processing' DESC, FIELD(priority, 'high', 'normal', 'low'), create_time DESC 
LIMIT #{offset}, #{pageSize}

